// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }
	// if end date is set, compare to start date
	if(g_form.getValue("u_start_date")){
		var jsStartDate = new Date(g_form.getValue("u_start_date"));
		var jsEndDate = new Date(newValue);
		if(jsStartDate > jsEndDate){
			g_form.setValue("u_end_date", "");
			g_form.showErrorBox("u_end_date", getMessage("Tasker - The End Date must be after the Start Date"), true);
		}
	}
}
